from __future__ import annotations

import time
from collections import OrderedDict


class TTLCache:
    def __init__(self, max_size: int, ttl_seconds: float, *, now=None):
        if max_size <= 0 or ttl_seconds <= 0:
            raise ValueError('max_size and ttl_seconds must be positive')
        self.max_size = max_size
        self.ttl = ttl_seconds
        self.now = now or time.monotonic
        self.data = OrderedDict()

    def set(self, key, value):
        self.data[key] = (value, self.now())
        self.data.move_to_end(key)
        while len(self.data) > self.max_size:
            self.data.popitem(last=False)

    def warm(self, initial: dict):
        for key, value in initial.items():
            self.set(key, value)

    def get(self, key):
        if key not in self.data:
            return None
        value, stamp = self.data[key]
        if self.now() - stamp > self.ttl:
            del self.data[key]
            return None
        self.data.move_to_end(key)
        return value

